INSERT INTO `texts` VALUES (1,1,'Metin 1','suç toplumda oluşan düzenin devamını sağlamak ve temel haklar ile özgürlüklerin korunabilmesi için gereken hukuki değerlerin ihlal edilmesi şeklinde haksızlık oluşturan insan davranışlarıdır bu davranışlar ceza hukuku yaptırımlarına tabi tutulan ve kanunun karşılığında ceza yaptırımı öngördüğü fiillerdir suç teşkil eden fiil bir hakkı ihlal ettiği için haksızlık teşkil eder dolayısıyla her suç aynı zamanda haksızlık teşkil etmektedir ancak her haksızlık suç değildir suç içeriği bakımından kanun koyucunun inancına göre devletin amaçlarıyla çatıştığından yaptırım olarak ceza veya güvenlik tedbirlerini gerektiren fiil kapsamındadır bir fiilin suç olup olmadığını belirlemek kanun koyucuya aittir suçla ilgili temel kavramlar şunlardır fail cezai nitelikteki hukuka aykırı fiili işleyen kişidir yaralama hırsızlık ve dolandırıcılık suçlarında olduğu gibi suçların çoğunluğu herhangi bir kimse tarafından işlenebilir bunlara genel suçlar denir bazı suçlarsa sadece belli hukuki veya fiili durumdaki kişiler tarafından işlenebilir bunlara ise mahsus suçlar denir her suçun faili olduğu gibi mutlaka hukuki konusu bulunmaktadır örneğin hırsızlık suçunun hukuki konusu zilyetlik yaralama suçunun hukuki konusu vücut bütünlüğü insan öldürme suçunun hukuki konusu yaşam hakkının ihlalleridir suçun maddi konularına bakacak olursak yalnızca maddi varlığı bulunan varlıklar üzerinde suç işlenebilir insan suçun maddi konusu olabilir tüzel kişiler topluluklar ve cismani varlığı olmayan şeyler suçun maddi konusunu oluşturamazlar örneğin hırsızlık suçunun maddi konusunu çalınan eşya oluştururken kasten öldürme suçunun maddi konusunu insan oluşturmaktadır mağdur insan toplum devlet ve tüzel kişiler olabilmektedir her suçun mutlaka mağduru vardır suçun mağdurları suç işlenirken hayatta olan kişilerdir kimse kendi kendisine karşı suç işleyemez örneğin intihar suç değildir ancak şikayete bağlı suçlarda şikayet hakkı kullanımı suçun mağduruna tanınmıştır suç devlete toplumun varlığına ve gelişimine ilişkin menfaatlerinin ihlalinden kaynaklanan sosyal zarar yanında doğrudan olarak zarar da doğurur bu zararlar her suçta mutlaka bulunmaktadır ihlal zarar verme şeklinde ya da tehlikeye düşürme şeklinde kendini göstermektedir suç işlenmesi nedeniyle mağdur olan kişi ile suçtan zarar gören kişi birbirinden farklılık göstermektedir','2026-06-21 12:07:50'),(2,1,'Metin 2','genel olarak kanunlarda suç olarak tanımlanan eylemleri işleyen kişilere verilen yaptırımlara ceza denir cezalar keyfi olmamalıdır hakkaniyete uygun insani herkese eşit olacak şekilde uygulanmalıdır verilen cezalarda toplum yararı gözetilmelidir genel olarak cezalar hapis cezası para cezası vücuda zarar verme hayata son verme veya fail tarafından bir şeyin yapılması şeklinde olabilir türk ceza kanununda bedensel veya hayata yönelik cezalar bulunmaz türk hukuk sisteminde işlenen suçların karşılığı olarak hapis cezaları veya adli para cezaları öngörülür türk hukuk sistemindeki cezaların temel özellikleri arasında cezaların şahsiliği ilkesi bulunmaktadır buna göre kişiler başka birinin işlediği fiiller nedeniyle sorumlu tutulamaz kanunilik ilkesi de cezaların başka bir özelliğidir ceza yasa koyucu tarafından kanunla konulup ancak kanunla kaldırılabilir yasa koyucu neyin suç olup olmayacağı suçların karşılığı cezaların neler olacağı konusunda takdir hakkına sahiptir ayrıca cezanın insan onuruyla bağdaşır nitelikte olması gerekir hiç kimse insan onuru ile bağdaşmayan bir ceza veya muameleye tabi tutulamaz ayrıca fiili gerçekleştiren kişiye verilen cezanın kişiye uydurulması gerekir buna cezanın bireyselleştirilmesi denir suç sayılan eylemler bazı şartlar altında gerçekleştirilirse suç olarak ifade edilmeyebilir bazı durumlarda da suç sayılmakla birlikte ceza indirimi yapılması ya da ceza verilmemesi sonucunu doğuran sebeplere hukuka uygunluk nedenleri denir bu durumlarda işlenen fiiller suç olmayıp kişiye ceza verilmesi uygun değildir ayrıca güvenlik tedbiri uygulanamaz bu kişiler hakkında dava açılmışsa beraat kararı verilir bazı hallerdeyse kişinin ceza sorumluluğu ortadan kalkar işlenen fiil nedeniyle failin hangi şartlarda sorumlu tutulacağının tespitinde kusur durumu önemlidir işlediği fiil ile ilgili kişideki irade gelişiminin şartları bu şartlara istinaden gerçekleştirdiği eylem nedeniyle failin şahsen cezalandırılması gerekmediği kusur durumu ile ilgilidir kanuni tanımda yer verilen suç failin kusur yeteneği olmasa bile işlenmiş olursa haksız bir fiildir ve suç niteliğini korur kanun koyucu faile bazı hallerde kusur yeteneği olmadığı için ceza verilmemesi gerektiğini bazı hallerdeyse kusur yeteneğinin zayıf olduğu için nispeten daha hafif ceza verilmesi gerektiğini kayıt altına almıştır','2026-06-21 12:07:50'),(3,1,'Metin 3','failin gerçekleştirmiş olduğu fiille ortaya çıkan sonuç arasında manevi bağ bulunur bu manevi bağ kusur olarak ifade edilir failin cezalandırılması için bağın türünün tespit edilmesi önemlidir örneğin akıl hastalığı bulunan kişinin işlediği suç fiilinin farkında olmaması durumunda cezalandırılması mümkün değildir suçun manevi unsurları olarak ifade edilen kast ve taksir kavramları failin gerçekleştirdiği fiille arasındaki nedensellik bağını ifade etmektedir kast kusurlu iradenin tipik gerçek şeklidir suç kanunu emrinin açıkça ihlalidir emrin ihlali failin yasaklanan fiili istemesi durumunda gerçekleşir kastın varlığı için sadece hareketin değil sonucun da istenmesi gerekir türk ceza kanununa göre kast suçun var olduğunu söyleyebilmek için kastın varlığı gereklidir kast ise suçun kanuni tanımındaki unsurların bilerek ve istenerek gerçekleşmesini ifade eder kastın varlığı suçun bütün aşamalarında aranır ceza kanunlarını bilmiyor olmak elbette mazeret olarak sayılmaz tüm kanunların herkes tarafından bilinmesini beklemek söz konusu olamaz hukuku meslek edinen kişilerin bile bunları ezbere bilmeleri veya suç olduğunu tahmin etmeleri mümkün değildir bu gibi durumlarda gerçekleştirilen fiilin icrası sırasında suçun kanuni tanımında sayılan maddi unsurları bilmeyen bir kişinin kasten hareket ettiği söylenemez suçun kanuni tanımında sayılan unsurların tamamı bilinmese bile ahlaki yönden yanlış olduğu bilinen eylemin suç olacağı ihtimalini kişi tahmin edebilmelidir örneğin yaralama veya hileli davranışlarla dolandırma herkes tarafından bilinen ahlaken de yanlış kabul edilen davranışlardır bu durumda kimse suçun kanuni tanımında bulunan unsurları bilmediğini öne süremez doğrudan kast bilerek ve istenerek suçun kanuni tanımında yer alan fiilin işlenmesidir örneğin pastanede bir kimseye ateş ederek öldüren kişi doğrudan kastla hareket etmiş ise insan öldürme suçunu işlemiş olur dolaylı kast suçun kanunda tanımlanan fiilin gerçekleşmesinin mümkün veya muhtemelen öngörülmesine rağmen neticenin meydana gelmesinin göze alınması şeklinde bir düşünce ile fiilin işlenmesidir örneğin pastanede ateş eden fail oranın kalabalık olması sebebi ile öldürmek istediği kişi dışında başka kişilerin de zarar görme ihtimalini düşünmelidir ateş sonucu başka kişileri de yaraladığında yaralama suçundan da ceza alır','2026-06-21 12:07:50'),(4,1,'Metin 4','taksir yasalarda öngörülen dikkat ve özen yükümlülüğü ihlalinden kaynaklanan öngörülebilir bir suçun kasıtsız olarak işlenmesidir taksir ile işlenen fiiller sadece kanunda açıkça belirtilen hallerde başvurulan sorumluluk şeklidir taksirde kusur ağırlığı kasıtlı suçlara göre daha azdır fail çoğu zaman kendisi de bir mağduriyet yaşar özellikle trafik kazalarında bu durum sıklıkla yaşanır dikkatli ve tedbirli davranarak ortaya konulması gereken irade yerine dikkatsiz ve tedbirsiz davranarak başka bir irade ortaya konulur taksirli sorumluluktan söz edebilmek için mutlaka zararlı neticenin gerçekleşmesi gerekir taksirle işlenen suç neticesinde verilecek olan ceza failin kusur oranına göre değişir basit taksir öngörülebilir neticeyi failin öngörememesi sonucunda ortaya çıkar failin dikkatli ve özenli olması gerekirken bu yükümlülüğe aykırı hareketle suç fiilini işlemesidir basit taksir için bilinçsiz taksir adi taksir gibi ifadeler de kullanılmaktadır örneğin gerekli iş güvenliği önlemlerini almayan bir fabrikada işçi çalıştıran işveren iş kazası neticesinde yaralamaya sebebiyet verirse basit taksirle yaralama suçunu işlemiş olur birden fazla kişinin taksirle işlediği suçlarda herkes kendi kusurundan dolayı sorumlu olur her failin cezası kendi kusur oranlarına göre ayrı ayrı belirlenir bilinçli taksir failin öngörüsüne rağmen neticenin gerçekleşmesini istemeyip kural ihlali yapıp ya da şans kişisel yetenek gibi etkilere güvenerek hareket etmesiyle suç fiilini işlemesidir fail sonucun meydana gelebileceğini öngörmesine rağmen sonucun gerçekleşmeyeceği inancıyla hareket eder örneğin sollamanın yasak olduğu yolda bu yasağa uymayıp şoförlüğüne güvenerek sollama yapan ve ölüme sebebiyet veren kişiye bilinçli taksirle ölüme neden olma suçundan dolayı ceza verilir taksirli hareketle sebep olunan olayda failin kişisel ve ailevi durumu artık cezanın verilmesini anlamsız kılacak kadar mağdur olmasına neden olursa ceza verilmez taksirle işlenen suçlarda kanundaki tanımında kastın unsurlarından bilerek ve istenerek işlenmesi yer almaz taksirden bahsedebilmek için failin suç işlerken suç işlemek amacıyla hareket etmemiş olması gerekir kastla taksir arasındaki önemli ayrım isteme unsurudur kanunun fiilin taksirle işlenen şeklini doğrudan suç olarak kabul etmediği durumlarda taksirle işlenen fiilin suç olarak kabulü mümkün değildir','2026-06-21 12:07:50'),(5,1,'Metin 5','kişi işlemeyi kastettiği bir suçu elverişli hareketlerle doğrudan doğruya icrasına başlayıp elinde olmayan nedenlerle tamamlamazsa teşebbüsten dolayı sorumlu olur suç genelde fiilin işlenmesi ve neticenin meydana gelmesi ile sonuçlanır suçun tam olarak gerçekleşmediği durumlarda da suç genel tanımının dışında kalır işlenen suç tamamlanmaz veya suç unsurlarının eksik olması nedeniyle suçun hukuk tanımına uymaması durumunda suçun özel görünüş şekillerinden bahsetmek gerekir teşebbüs suçun özel görünüş şekillerinden biridir suç yolunda ilerleyen fail çeşitli aşamalardan geçer suç yolunda icra ve tamamlama aşaması olmak üzere iki aşama vardır kasıtlı işlenen suçlarda bahsedilen aşamalara düşünce aşaması da eklenir bu aşama icra aşamasından önce gelir bazen de tamamlanma aşamasını son bulma aşaması takip eder böylece suç yolunda dört aşama vardır denilebilir düşünce aşaması ceza hukukunu ilgilendirmez eyleme dönüşmeyen hiçbir düşünce cezalandırılamaz icra aşamasına geçilmesiyle ceza hukukunun alanına girilir düşüncenin somutlaştırılarak dış dünyada eyleme dönüşmesi her zaman o suçun icrasının başladığı anlamına gelmez bu aşamada da hazırlık hareketleri icra hareketleri ayırımı yapılır hazırlık aşaması kural olarak cezalandırılmaz ancak bazı istisna teşkil eden suçların hazırlık hareketleri cezalandırılabilir icra aşamasında failin suç işleme düşüncesi icrai veya ihmali bir hareketle somutlaşır icra aşamasından sonra tamamlama aşaması gelir tamamlanmış suç fail tarafından işlenen somut fiilin kanundaki soyut tanıma uymasını ifade etmektedir fiil suç tanımına uygun bulunduğu anda suç tamamlanır teşebbüs aşamasında kalmış suçu tam tamamlanmış suçtan ayıran nokta tamamlanma anının yokluğudur suçun tamamlanması ile son bulması aynı olabileceği gibi bazen çakışmayabilir örneğin tokat atıldığında yaralama suçu oluşarak tamamlanır birden fazla tokat atıldığında son tokadın atılmasıyla suç tamamlanmış olur aslında ilk tokadın atılmasıyla suç zaten tamamlanmıştır bütün unsurları tamamlanmış suçla teşebbüs aşamasında kalmış suç arasında manevi unsur yönünden fark yoktur her ikisi de suç sayılan belirli bir sonuca ulaşabilmek amacı ile işlenir teşebbüste eksik failin iradesi dışında kalan nedenle bu sonuca götürecek hareketlerin bitmesi veya biten hareketlerden hedeflenen sonucun oluşmasına engel olmasıdır','2026-06-21 12:07:50'),(6,1,'Metin 6','failin suçun icra eyleminden kendi isteğiyle vazgeçmesi ya da kendi çabası sonucu suçun tamamlanmasını veya sonucun gerçekleşmesini önlemesi gönüllü vazgeçme şeklinde ifade edilir gönüllü vazgeçmede fail suç yolunda sonuna kadar ilerleme imkanına sahipken kendi isteği ile devam etmek istemez gönüllü vazgeçen kişi teşebbüsten dolayı cezalandırılmaz eylemin tamamlanmış olan kısmı eğer herhangi bir suç oluşturursa bu durumda sadece o suça ait ceza ile cezalandırılır gönüllü vazgeçmede fail icra hareketlerine devam edebilecek ve neticeyi gerçekleştirebilecek imkana sahiptir ancak bunu istememektedir neticeyi gerçekleştirme ve devam etme isteğinin olmasına rağmen bu eylemi gerçekleştiremiyorsa gönüllü vazgeçme yoktur saik önemli değildir mağdura duyduğu acıma cezadan korkma günah işleme düşüncesi toplumsal dışlanma endişesi gibi nedenlerle vazgeçme olabilir vazgeçme failin özgür iradesi ile olmalıdır dışarıdan gelen maddi veya manevi baskı altında vazgeçen kişi gönüllü vazgeçmiş olmaz failin iradesi zorlanmış olmamalıdır örneğin failin hırsızlık yapmak için girdiği evde ev sahibine acıyarak ya da günah işleme düşüncesi ile icra hareketlerini tamamlamaktan vazgeçtiği durumda bu vazgeçme gönüllü gerçekleşmiştir sadece tamamlanan kısım suç oluşturuyorsa fail o kısımdan sorumlu olur verilen örnekte fail sadece konut dokunulmazlığının ihlalinden sorumlu olur ancak güvenlik görevlisinin düdüğünü duyduktan sonra pencereden atlayan failin vazgeçme eylemi gönüllü olmayıp fail hırsızlığa teşebbüs suçundan dolayı cezalandırılır failin fiilini sona erdirmesine herhangi bir neden engel olacak şekilde sebep olmuşsa ve bu nedenle fail amacına ulaşamayacağını anlayarak eyleme devam etmeyi bırakmışsa gönüllü vazgeçme yoktur devam etme imkanı olmalı ve kendi iradesiyle kullanmaktan vazgeçmiş olmalıdır failin pişman olurken samimi olması şart değildir ceza korkusu üçüncü kişilerin tavsiyesi veya acıma gibi nedenler failin vazgeçme sebepleri arasındadır etkin pişmanlık kişinin işlemiş olduğu suçlardan dolayı kendi isteğiyle sonradan pişman olması suç teşkil eden fiilin meydana g